**Test 5: feedback with a solvable constraint queues inputs.** This requires constructing an ExecuteResult with a solvable SymExpr constraint. Use a simple `Param { index: 0, name: "x" } == Const(Int(5))` constraint where negation should yield `x != 5` (Sat with some other value).

```rust
#[test]
fn z3_solver_feedback_with_solvable_constraint_queues_input() {
    use crate::execution_record::{BranchDecision, SymConstraint};
    use crate::sym_expr::{SymExpr, ConstValue, BinOpKind};

    let param = ParamInfo {
        name: "x".into(),
        typ: TypeInfo::Int,
        type_name: None,
    };
    let mut s = Z3SolverStrategy::new(Some(1000), vec![param]);
    let ctx = empty_ctx();

    // Constraint: x == 5 (taken=true), so solver will negate to x != 5
    let constraint = SymExpr::BinOp {
        op: BinOpKind::Eq,
        left: Box::new(SymExpr::Param { index: 0, name: "x".into() }),
        right: Box::new(SymExpr::Const(ConstValue::Int(5))),
    };
    let mut result = make_exec_result();
    result.branch_path = vec![BranchDecision {
        branch_id: 1,
        taken: true,
        location: None,
        constraint: SymConstraint::Expr { expr: constraint },
        branch_type: None,
    }];

    s.feedback(&[Value::from(5)], &result, false);
    // Should have queued at least one input (the negated constraint is SAT).
    assert!(s.next(&ctx).is_some());
}
```

